

/* ═══ Browse Mode Styles ═══ */

.browse-toolbar {
  display: flex;
  align-items: center;
  gap: 8px;
  flex-wrap: wrap;
  padding: 8px 12px;
}

.browse-search {
  flex: 1;
  min-width: 120px;
  max-width: 320px;
}

.browse-mode-switch {
  display: flex;
  border-radius: 8px;
  overflow: hidden;
  border: 1px solid var(--wb-border-main);
  margin-left: auto;
}

.browse-mode-btn {
  border-radius: 0 !important;
  border: none !important;
  font-size: 12px;
  padding: 4px 12px;
  background: transparent;
  color: var(--wb-text-muted);
  transition: all 0.2s ease;
}

.browse-mode-btn.active {
  background: var(--wb-accent);
  color: #fff;
}

.browse-bindings {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 4px 12px;
  flex-wrap: wrap;
  font-size: 12px;
}

.binding-tag {
  padding: 2px 8px;
  border-radius: 12px;
  font-size: 11px;
  font-weight: 500;
}

.binding-tag.global {
  background: rgba(34, 197, 94, 0.15);
  color: #4ade80;
}

.binding-tag.char {
  background: rgba(59, 130, 246, 0.15);
  color: #60a5fa;
}

.binding-tag.chat {
  background: rgba(234, 179, 8, 0.15);
  color: #facc15;
}

.browse-entry-count {
  color: var(--wb-text-muted);
  font-size: 11px;
}

.browse-action-bar {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 4px 12px;
  flex-wrap: wrap;
  font-size: 12px;
}

.browse-action-spacer {
  flex: 1;
}

.browse-scroll-area {
  flex: 1;
  min-height: 0;
  overflow-y: auto;
  overflow-x: hidden;
  padding: 0 12px 12px;
}

.browse-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));
  gap: 12px;
  align-items: stretch;
}

.browse-card {
  background: var(--wb-bg-card, rgba(255, 255, 255, 0.04));
  border: 1px solid var(--wb-border-main);
  border-radius: 10px;
  padding: 12px;
  display: flex;
  flex-direction: column;
  gap: 6px;
  cursor: pointer;
  transition: all 0.2s ease;
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
}

.browse-card:hover {
  border-color: var(--wb-accent);
  box-shadow: 0 0 12px rgba(var(--wb-accent-rgb, 56, 189, 248), 0.15);
}

.browse-card.expanded {
  cursor: default;
  grid-column: 1 / -1;
  border-color: var(--wb-accent);
  box-shadow: 0 0 20px rgba(var(--wb-accent-rgb, 56, 189, 248), 0.1);
}

.browse-card.disabled {
  opacity: 0.55;
}

.browse-card-header {
  display: flex;
  align-items: center;
  gap: 8px;
}

.browse-card-title {
  flex: 1;
  font-weight: 600;
  font-size: 13px;
  color: var(--wb-text-main);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.browse-toggle-wrap {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  cursor: pointer;
  font-size: 11px;
  flex-shrink: 0;
}

.browse-toggle-wrap input[type="checkbox"] {
  accent-color: var(--wb-accent);
}

.browse-toggle-label {
  color: var(--wb-text-muted);
  font-weight: 600;
  font-size: 10px;
  text-transform: uppercase;
}

.browse-card-keys {
  display: flex;
  gap: 4px;
  flex-wrap: wrap;
}

.browse-key-chip {
  padding: 1px 6px;
  border-radius: 4px;
  font-size: 10px;
  background: rgba(255, 255, 255, 0.06);
  color: var(--wb-text-muted);
  border: 1px solid rgba(255, 255, 255, 0.08);
}

.browse-key-chip.more {
  background: transparent;
  color: var(--wb-accent);
  border-color: var(--wb-accent);
}

.browse-card-preview {
  font-size: 12px;
  color: var(--wb-text-muted);
  line-height: 1.5;
  max-height: clamp(3em, 8vh, 8em);
  overflow: hidden;
  white-space: pre-wrap;
  word-break: break-word;
  mask-image: linear-gradient(to bottom, black 60%, transparent 100%);
  -webkit-mask-image: linear-gradient(to bottom, black 60%, transparent 100%);
}

.browse-card-meta {
  display: flex;
  gap: 6px;
  flex-wrap: wrap;
  margin-top: 2px;
}

.browse-meta-pill {
  padding: 1px 8px;
  border-radius: 6px;
  font-size: 10px;
  background: rgba(255, 255, 255, 0.06);
  color: var(--wb-text-muted);
}

.browse-meta-pill[data-status="constant"] {
  background: rgba(59, 130, 246, 0.12);
  color: #60a5fa;
}

.browse-meta-pill[data-status="selective"] {
  background: rgba(34, 197, 94, 0.12);
  color: #4ade80;
}

/* Expanded card inline editor */

.browse-card-expanded {
  display: flex;
  flex-direction: column;
  gap: 6px;
  padding-top: 8px;
  border-top: 1px solid var(--wb-border-main);
  margin-top: 4px;
}

.browse-keys-input {
  resize: vertical;
  min-height: 24px;
  font-size: 12px;
}

.browse-secondary-keys-row {
  display: flex;
  gap: 6px;
}

.browse-secondary-keys-row select {
  width: 110px;
  flex-shrink: 0;
}

.browse-secondary-keys-row textarea {
  flex: 1;
}

.browse-content-input {
  resize: vertical;
  min-height: 280px;
  max-height: 70vh;
  font-size: 12px;
  font-family: inherit;
  line-height: 1.5;
}

.browse-config-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
  gap: 8px;
}

.browse-recursion-row {
  display: flex;
  gap: 16px;
  flex-wrap: wrap;
}

.browse-card-actions {
  display: flex;
  gap: 6px;
  flex-wrap: wrap;
  padding-top: 6px;
  border-top: 1px solid var(--wb-border-main);
}

.browse-card-actions .btn:last-child {
  margin-left: auto;
}

.browse-empty {
  grid-column: 1 / -1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 48px 16px;
  color: var(--wb-text-muted);
  gap: 8px;
}

.browse-empty-icon {
  font-size: 40px;
  opacity: 0.4;
}

.browse-empty-text {
  font-size: 14px;
}

/* Glow pulse for unsaved changes */
@keyframes glow-pulse {
  0%, 100% { box-shadow: 0 0 4px rgba(var(--wb-accent-rgb, 56, 189, 248), 0.3); }
  50% { box-shadow: 0 0 12px rgba(var(--wb-accent-rgb, 56, 189, 248), 0.7); }
}

.glow-pulse {
  animation: glow-pulse 2s ease-in-out infinite;
}

/* Mobile browse overrides */

.mobile-browse-view {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-height: 0;
}

.mobile-browse-toolbar {
  padding: 6px 8px;
  gap: 6px;
}

.mobile-browse-toolbar .worldbook-picker {
  max-width: 160px;
}

.mobile-browse-toolbar .browse-search {
  max-width: none;
  min-width: 80px;
}

.mobile-browse-scroll {
  padding: 0 8px 8px;
}

.mobile-browse-bindings {
  padding: 4px 0;
}

.mobile-browse-grid {
  grid-template-columns: 1fr;
  gap: 8px;
}

.mobile-browse-grid .browse-card.expanded {
  grid-column: auto;
}

.mobile-config-grid {
  grid-template-columns: 1fr 1fr;
}

.browse-global-mode {
  padding: 8px 12px;
}

.hidden-input {
  position: absolute;
  opacity: 0;
  width: 0;
  height: 0;
  overflow: hidden;
  pointer-events: none;
}

/* Load more sentinel */

.browse-load-more-sentinel {
  grid-column: 1 / -1;
  display: flex;
  justify-content: center;
  padding: 16px;
}

.browse-load-more-text {
  font-size: 12px;
  color: var(--wb-text-muted);
  opacity: 0.6;
}

/* ═══ End Browse Mode Styles ═══ */

.wb-assistant-root {
  position: relative;
  flex: 1;
  min-height: 0;
  width: 100%;
  box-sizing: border-box;
  display: flex;
  flex-direction: column;
  padding: 12px;
  gap: 12px;
  background: var(--wb-bg-root);
  color: var(--wb-text-main);
  font-size: 13px;
  line-height: 1.5;
  border-radius: 12px;
  overflow: hidden;
}

/* Glassmorphism Styles */
.wb-assistant-root.is-glass-mode {
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
}

.wb-assistant-root.is-glass-mode .wb-editor-container,
.wb-assistant-root.is-glass-mode .wb-layout-sidebar,
.wb-assistant-root.is-glass-mode .wb-entry-list,
.wb-assistant-root.is-glass-mode .st-utility-panel,
.wb-assistant-root.is-glass-mode .wb-modal-window {
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border-color: color-mix(in srgb, var(--wb-border-main) 50%, transparent);
}
.wb-assistant-root.is-glass-mode .utility-btn {
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
}

.focus-cine-overlay {
  position: absolute;
  inset: 0;
  z-index: 10290;
  pointer-events: auto;
  overflow: hidden;
}

.focus-cine-overlay::before {
  content: '';
  position: absolute;
  inset: 0;
  background:
    radial-gradient(circle at 50% 40%, rgba(125, 211, 252, 0.14), rgba(2, 6, 23, 0.42) 72%),
    radial-gradient(circle at 50% 50%, rgba(2, 6, 23, 0), rgba(2, 6, 23, 0.42) 100%);
  animation: focus-cine-vignette 1400ms cubic-bezier(0.22, 1, 0.36, 1) both;
}

.copy-cine-overlay {
  position: absolute;
  inset: 0;
  z-index: 10292;
  pointer-events: auto;
  overflow: hidden;
}

.copy-cine-overlay::before {
  content: '';
  position: absolute;
  inset: 0;
  background:
    radial-gradient(circle at 52% 46%, rgba(125, 211, 252, 0.12), rgba(2, 6, 23, 0.46) 70%),
    radial-gradient(circle at 48% 60%, rgba(2, 6, 23, 0), rgba(2, 6, 23, 0.38) 100%);
  animation: copy-cine-vignette 1100ms cubic-bezier(0.22, 1, 0.36, 1) both;
}

.focus-cine-ghost {
  position: fixed;
  z-index: 10305;
  margin: 0;
  pointer-events: none;
  transform-origin: center center;
  will-change: transform, opacity, filter;
  filter: drop-shadow(0 10px 20px rgba(2, 6, 23, 0.45));
  animation-name: focus-cine-hero-flight;
  animation-fill-mode: forwards;
}

.copy-cine-ghost {
  position: fixed;
  z-index: 10308;
  margin: 0;
  pointer-events: none;
  transform-origin: center center;
  will-change: transform, opacity, filter;
  filter: drop-shadow(0 10px 20px rgba(2, 6, 23, 0.42));
  animation-name: copy-cine-hero-flight;
  animation-fill-mode: forwards;
}

[data-focus-hero].focus-cine-real-hidden {
  visibility: hidden !important;
}

[data-copy-hero].copy-cine-real-hidden {
  visibility: hidden !important;
}

@keyframes focus-cine-vignette {
  0% {
    opacity: 0;
  }
  35% {
    opacity: 0.86;
  }
  100% {
    opacity: 0.2;
  }
}

@keyframes focus-cine-hero-flight {
  0% {
    opacity: var(--cine-from-opacity, 1);
    transform: translate3d(0, 0, 0) scale(1, 1);
  }
  60% {
    opacity: 1;
    transform: translate3d(calc(var(--cine-dx, 0px) * 0.6), calc(var(--cine-dy, 0px) * 0.6 + var(--cine-arc-y, -20px)), 0)
      scale(calc(var(--cine-scale-x, 1) * 1.04), calc(var(--cine-scale-y, 1) * 1.04));
  }
  100% {
    opacity: var(--cine-to-opacity, 1);
    transform: translate3d(var(--cine-dx, 0px), var(--cine-dy, 0px), 0) scale(var(--cine-scale-x, 1), var(--cine-scale-y, 1));
  }
}

@keyframes copy-cine-vignette {
  0% {
    opacity: 0;
  }
  40% {
    opacity: 0.8;
  }
  100% {
    opacity: 0.16;
  }
}

@keyframes copy-cine-hero-flight {
  0% {
    opacity: var(--copy-cine-from-opacity, 1);
    transform: translate3d(0, 0, 0) scale(1, 1);
  }
  60% {
    opacity: 1;
    transform: translate3d(
      calc(var(--copy-cine-dx, 0px) * 0.62),
      calc(var(--copy-cine-dy, 0px) * 0.62 + var(--copy-cine-arc-y, -12px)),
      0
    ) scale(
      calc(var(--copy-cine-scale-x, 1) * 1.03),
      calc(var(--copy-cine-scale-y, 1) * 1.03)
    );
  }
  100% {
    opacity: var(--copy-cine-to-opacity, 1);
    transform: translate3d(var(--copy-cine-dx, 0px), var(--copy-cine-dy, 0px), 0) scale(var(--copy-cine-scale-x, 1), var(--copy-cine-scale-y, 1));
  }
}


.wb-scroll-area {
  flex: 1;
  min-height: 0;
  overflow-y: auto;
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.wb-scroll-area.copy-workspace {
  overflow: hidden;
}

.wb-settings-wrapper {
  width: 100%;
}

.cross-copy-panel {
  border: 1px solid var(--wb-border-subtle);
  border-radius: 12px;
  background: var(--wb-bg-panel);
  padding: 12px;
  display: grid;
  gap: 10px;
  min-height: 0;
  overflow: hidden;
}

.cross-copy-panel.mobile {
  padding: 10px;
  gap: 8px;
  display: flex;
  flex-direction: column;
  min-height: 0;
  height: 100%;
}

.cross-copy-panel.desktop {
  height: clamp(620px, calc(100vh - 220px), 82vh);
  max-height: calc(100vh - 110px);
  grid-template-rows: auto auto minmax(0, 1fr) auto;
}

.cross-copy-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  font-size: 13px;
  flex-wrap: wrap;
}

.cross-copy-head-main {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  min-width: 0;
}

.cross-copy-head-main span {
  color: var(--wb-text-muted);
  font-size: 12px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.cross-copy-head-actions {
  position: relative;
  display: inline-flex;
  align-items: center;
  gap: 8px;
  min-width: 0;
}

.copy-cine-sink-cluster {
  position: absolute;
  right: 0;
  top: 50%;
  width: 0;
  height: 0;
  opacity: 0;
  pointer-events: none;
  z-index: 0;
}

.copy-cine-sink {
  width: 86px;
  height: 34px;
  border-radius: 8px;
}

.copy-cine-sink-cluster .copy-cine-sink {
  position: absolute;
  right: 0;
  top: 0;
  transform: translateY(-50%);
}

.copy-cine-sink-cluster.workspace {
  left: 50%;
  right: auto;
}

.copy-cine-sink-cluster.workspace .copy-cine-sink {
  left: 0;
  right: auto;
  transform: translate(-50%, -50%);
}

.cross-copy-head strong {
  font-size: 15px;
}

.cross-copy-head span {
  color: var(--wb-text-muted);
  font-size: 12px;
}

.cross-copy-controls-wrap {
  display: grid;
  gap: 8px;
}

.cross-copy-controls {
  display: grid;
  grid-template-columns: repeat(2, minmax(220px, 1fr));
  gap: 8px 10px;
  align-items: center;
}

.cross-copy-panel.mobile .cross-copy-controls {
  grid-template-columns: minmax(0, 1fr);
}

.cross-copy-controls-primary {
  grid-template-columns: repeat(2, minmax(220px, 1fr)) auto;
}

.cross-copy-controls-advanced {
  grid-template-columns: repeat(2, minmax(240px, 1fr));
  padding: 8px 10px;
  border: 1px solid var(--wb-border-subtle);
  border-radius: 10px;
  background: rgba(0, 0, 0, 0.16);
}

.cross-copy-control-actions {
  display: flex;
  justify-content: flex-end;
  align-items: end;
}

.cross-copy-panel.mobile .cross-copy-control-actions {
  justify-content: flex-start;
}

.cross-copy-inline-tips {
  display: grid;
  gap: 6px;
}

.cross-copy-inline-tip {
  border-radius: 8px;
  border: 1px solid var(--wb-border-subtle);
  padding: 6px 8px;
  font-size: 12px;
  background: var(--wb-input-bg);
}

.cross-copy-inline-tip.warning {
  color: #f59e0b;
}

.cross-copy-inline-tip.success {
  color: #34d399;
}

.copy-controls-advanced-enter-active,
.copy-controls-advanced-leave-active {
  transition: opacity 200ms ease, transform 220ms cubic-bezier(0.22, 1, 0.36, 1), max-height 220ms ease;
  overflow: hidden;
}

.copy-controls-advanced-enter-from,
.copy-controls-advanced-leave-to {
  opacity: 0;
  transform: translateY(-6px);
  max-height: 0;
}

.copy-controls-advanced-enter-to,
.copy-controls-advanced-leave-from {
  opacity: 1;
  transform: translateY(0);
  max-height: 180px;
}

.cross-copy-grid {
  display: grid;
  grid-template-columns: minmax(260px, 320px) minmax(0, 1fr);
  gap: 10px;
  min-height: 0;
  flex: 1;
}

.cross-copy-grid.single-column {
  grid-template-columns: minmax(0, 1fr) !important;
}

.cross-copy-grid.mobile {
  grid-template-columns: minmax(0, 1fr);
}

.cross-copy-splitter {
  width: 100%;
  min-height: 0;
  border-radius: 999px;
  background: color-mix(in srgb, var(--wb-border-main) 68%, transparent);
  cursor: col-resize;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--wb-text-muted);
  user-select: none;
  touch-action: none;
  transition: background 160ms ease, color 160ms ease;
}

.cross-copy-splitter:hover,
.cross-copy-splitter.dragging {
  background: color-mix(in srgb, var(--wb-primary) 50%, transparent);
  color: var(--wb-primary-light);
}

.cross-copy-left,
.cross-copy-right {
  border: 1px solid var(--wb-border-subtle);
  border-radius: 10px;
  padding: 8px;
  background: rgba(0, 0, 0, 0.12);
  display: flex;
  flex-direction: column;
  gap: 6px;
  min-height: 0;
}

.cross-copy-list-head {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 8px;
  font-size: 12px;
}

.cross-copy-list-head strong {
  font-size: 13px;
}

.cross-copy-list-head span {
  color: var(--wb-text-muted);
}

.cross-copy-list-tools {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.cross-copy-mini-actions {
  display: flex;
  gap: 6px;
  flex-wrap: wrap;
}

.cross-copy-source-list,
.cross-copy-rows {
  min-height: 0;
  overflow: auto;
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.cross-copy-source-item {
  display: flex;
  align-items: center;
  gap: 8px;
  border: 1px solid var(--wb-border-subtle);
  border-radius: 8px;
  padding: 7px 8px;
  cursor: pointer;
  background: var(--wb-input-bg);
}

.cross-copy-source-item.checked {
  border-color: var(--wb-primary);
  box-shadow: 0 0 0 1px color-mix(in srgb, var(--wb-primary) 35%, transparent);
}

.cross-copy-source-name {
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.cross-copy-status-dot,
.cross-copy-status-badge {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border-radius: 999px;
  border: 1px solid transparent;
}

.cross-copy-status-dot {
  width: 10px;
  height: 10px;
  flex-shrink: 0;
}

.cross-copy-status-badge {
  padding: 2px 8px;
  font-size: 11px;
}

.cross-copy-status-dot.new,
.cross-copy-status-badge.new {
  background: rgba(34, 197, 94, 0.2);
  border-color: rgba(34, 197, 94, 0.5);
  color: #22c55e;
}

.cross-copy-status-dot.changed,
.cross-copy-status-badge.changed {
  background: rgba(59, 130, 246, 0.2);
  border-color: rgba(59, 130, 246, 0.5);
  color: #60a5fa;
}

.cross-copy-status-dot.duplicate,
.cross-copy-status-badge.duplicate {
  background: rgba(245, 158, 11, 0.2);
  border-color: rgba(245, 158, 11, 0.5);
  color: #f59e0b;
}

.cross-copy-status-dot.content-duplicate,
.cross-copy-status-badge.content-duplicate {
  background: rgba(168, 85, 247, 0.22);
  border-color: rgba(168, 85, 247, 0.5);
  color: #c084fc;
}

.cross-copy-status-dot.invalid,
.cross-copy-status-badge.invalid {
  background: rgba(239, 68, 68, 0.2);
  border-color: rgba(239, 68, 68, 0.5);
  color: #f87171;
}

.cross-copy-row {
  border: 1px solid var(--wb-border-subtle);
  border-radius: 10px;
  padding: 6px 8px;
  background: var(--wb-input-bg);
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.cross-copy-row-head {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 8px;
}

.cross-copy-row-title {
  display: flex;
  align-items: center;
  gap: 6px;
  min-width: 0;
}

.cross-copy-row-title strong {
