  gap: 8px;
  background: var(--wb-bg-panel);
  border: 1px solid var(--wb-border-subtle);
  transition: padding 240ms cubic-bezier(0.22, 1, 0.36, 1);
}

.wb-focus-toolbar.compact {
  padding: 8px 10px;
}

.wb-focus-toolbar-row {
  display: flex;
