}

.entry-item.drop-before::after,
.entry-item.drop-after::after {
  content: '';
  position: absolute;
  left: 8px;
  right: 8px;
  height: 2px;
  border-radius: 999px;
  background: var(--wb-primary-light);
  box-shadow: 0 0 0 1px color-mix(in srgb, var(--wb-primary-light) 65%, transparent);
  pointer-events: none;
}

.entry-item.drop-before::after {
  top: -2px;
}

.entry-item.drop-after::after {
  bottom: -2px;
}

.entry-item.disabled {
