  display: flex;
  align-items: center;
  justify-content: center;
  user-select: none;
  touch-action: none;
}

.wb-history-pane-splitter::before {
  content: '';
  position: absolute;
  left: 4px;
  right: 4px;
  top: 50%;
  height: 1px;
  background: var(--wb-border-main);
  transform: translateY(-50%);
}

.wb-history-pane-splitter-grip {
  position: relative;
  z-index: 1;
  font-size: 10px;
  color: var(--wb-text-muted);
  letter-spacing: 1px;
  background: var(--wb-bg-panel);
  border-radius: 999px;
  padding: 0 6px;
  border: 1px solid var(--wb-border-subtle);
}

.wb-history-pane-splitter:hover .wb-history-pane-splitter-grip {
  color: var(--wb-primary-light);
  border-color: var(--wb-primary);
}

.wb-history-diff-title {
  padding: 8px 10px;
  border-bottom: 1px solid var(--wb-border-main);
  font-size: 11px;
  color: var(--wb-primary-light);
}

.wb-worldbook-compare-list {
  min-height: 0;
  max-height: 240px;
  overflow: auto;
  display: flex;
  flex-direction: column;
  gap: 6px;
  padding: 8px 10px;
}

.wb-worldbook-compare-row {
  width: 100%;
  border: 1px solid var(--wb-border-subtle);
  border-radius: 8px;
  background: var(--wb-input-bg);
  color: var(--wb-text-main);
  padding: 8px;
  text-align: left;
  display: flex;
  flex-direction: column;
  gap: 4px;
  cursor: pointer;
}

.wb-worldbook-compare-row.active {
  border-color: var(--wb-primary);
  box-shadow: 0 0 0 1px color-mix(in srgb, var(--wb-primary) 32%, transparent);
}

.wb-worldbook-compare-row-head {
  display: flex;
  align-items: center;
  gap: 6px;
  min-width: 0;
}

.wb-worldbook-compare-row-head strong {
  min-width: 0;
  flex: 1 1 auto;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.wb-worldbook-compare-row-note {
  font-size: 12px;
  color: var(--wb-text-muted);
}

.wb-worldbook-detail-empty {
  border: 1px dashed var(--wb-border-subtle);
  border-radius: 10px;
  padding: 10px;
  background: var(--wb-input-bg);
}

@media (max-width: 1380px) {
  .wb-editor-shell {
    grid-template-columns: 1fr;
  }

  .editor-side {
    overflow: visible;
    max-height: none;
  }

  .wb-history-modal-main {
    grid-template-columns: 1fr;
  }

  .wb-history-versions {
    border-right: none;
    border-bottom: 1px solid var(--wb-border-main);
    max-height: 120px;
  }

  .wb-modal-backdrop {
    padding: 2px;
  }

  .wb-history-modal {
    width: 100%;
    max-height: calc(100vh - 4px);
    height: calc(100vh - 4px);
    border-radius: 6px;
  }

  .wb-history-modal-header {
    flex-wrap: wrap;
    gap: 4px;
    padding: 6px 8px;
    flex-shrink: 0;
  }

  .wb-history-modal-header strong {
    font-size: 12px;
  }

  .wb-history-modal-header > div:first-child span {
    display: none;
  }

  .wb-history-modal-actions {
    gap: 4px;
  }

  .wb-history-modal-actions .btn {
    font-size: 10px;
    padding: 3px 6px;
  }

  .wb-history-modal-main {
    grid-template-columns: 1fr;
    overflow-y: auto;
    flex: 1;
    min-height: 0;
  }

  .wb-history-diff-wrap {
    overflow-y: auto;
    min-height: 0;
  }

  .wb-history-visual-main {
    overflow: auto;
    gap: 8px;
    padding: 8px;
  }

  .wb-history-resizable-layout {
    overflow: visible;
    gap: 8px;
  }

  .wb-history-pane-section {
    overflow: visible;
    flex: 0 0 auto !important;
  }

  .wb-history-pane-section > .cross-copy-preview-grid,
  .wb-history-pane-section > .cross-copy-visual-section {
    height: auto;
  }

  .wb-history-pane-splitter {
    display: none;
  }

  .wb-history-version-preview {
    grid-template-columns: 1fr;
  }

  .wb-worldbook-compare-list {
    max-height: 180px;
  }

  .wb-history-visual-main .cross-copy-content-grid {
    grid-template-columns: 1fr;
  }

  .wb-history-visual-main .cross-copy-content-col + .cross-copy-content-col {
    border-left: none;
    border-top: 1px solid var(--wb-border-main);
  }

  .wb-history-visual-main .cross-copy-content-line {
    grid-template-columns: 1fr;
  }

  .wb-history-visual-main .cross-copy-content-line .line-no {
    display: none;
  }

  .wb-history-diff-head {
    flex-wrap: wrap;
    gap: 4px;
    padding: 6px 8px;
  }

  .wb-history-diff-head > div {
    font-size: 10px;
  }
}

@media (max-width: 1100px) {
  .global-mode-grid {
    grid-template-columns: 1fr;
  }

  .wb-resize-handle {
    display: none;
  }

  .wb-main-layout {
    grid-template-columns: 1fr;
  }

  .wb-tools-grid {
    grid-template-columns: 1fr;
  }

  .editor-grid.two-cols,
  .editor-grid.three-cols {
    grid-template-columns: 1fr;
  }

  .editor-head {
    flex-direction: column;
    align-items: stretch;
  }

  .editor-badges {
    justify-content: flex-start;
  }

  .history-preview-grid {
    grid-template-columns: 1fr;
  }

  .wb-history-visual-main .cross-copy-content-grid {
    grid-template-columns: 1fr;
  }

  .wb-history-visual-main .cross-copy-content-col + .cross-copy-content-col {
    border-left: none;
    border-top: 1px solid var(--wb-border-main);
  }

  .wb-status {
    flex-direction: column;
  }


  .wb-floating-window {
    width: calc(100vw - 16px) !important;
    left: 8px !important;
    right: 8px;
  }
}

.editor-back-btn {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 10px 12px;
  margin: 0 0 8px 0;
  background: var(--wb-bg-panel);
  border: none;
  border-radius: 6px;
  color: var(--wb-primary);
  font-weight: 600;
  cursor: pointer;
}

.editor-back-btn:hover {
  background: var(--wb-primary-hover);
}

/* ═══ Mobile Tab View ═══ */
.mobile-tab-view {
  display: flex;
  flex-direction: column;
  flex: 1;
  min-height: 0;
  overflow: hidden;
}

.mobile-tab-content {
  flex: 1;
  min-height: 0;
  position: relative;
}

.mobile-pane {
  position: absolute;
  inset: 0;
  overflow-y: auto;
  padding: 8px;
  -webkit-overflow-scrolling: touch;
}

.mobile-entry-list {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.mobile-multi-toolbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  flex-wrap: wrap;
  border: 1px solid var(--wb-border-subtle);
  border-radius: 8px;
  padding: 8px;
  background: var(--wb-bg-panel);
  margin-bottom: 4px;
}

.mobile-multi-title {
  font-size: 12px;
  color: var(--wb-primary-light);
}

.mobile-multi-actions {
  display: inline-flex;
  gap: 6px;
  flex-wrap: wrap;
}

.mobile-multi-item {
  position: relative;
}

.mobile-multi-checkbox {
  flex-shrink: 0;
}

.mobile-multi-content-note {
  margin-bottom: 6px;
  border: 1px solid rgba(245, 158, 11, 0.35);
  border-radius: 8px;
  padding: 6px 8px;
  font-size: 12px;
  color: #fbbf24;
  background: rgba(245, 158, 11, 0.08);
}

.mobile-ai-panel {
  height: 100%;
  display: flex;
  flex-direction: column;
}

.mobile-ai-panel .ai-chat-area {
  flex: 1;
  min-height: 0;
  display: flex;
  flex-direction: column;
}

.mobile-danger-zone {
  display: flex;
  gap: 8px;
  margin-top: 16px;
  padding-top: 16px;
  border-top: 1px solid var(--wb-border);
}

.mobile-danger-zone .btn {
  flex: 1;
}

.mobile-tab-bar {
  flex-shrink: 0;
  z-index: 10100;
  display: flex;
  border-top: 1px solid var(--wb-border-main);
  background: var(--wb-bg-panel);
  height: 52px;
}

.mobile-tab-bar button {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 2px;
  border: none;
  background: transparent;
  color: var(--wb-text-muted);
  font-size: 10px;
  padding: 4px 0;
  cursor: pointer;
  transition: color 0.15s, background 0.15s;
  -webkit-tap-highlight-color: transparent;
}

.mobile-tab-bar button.active {
  color: var(--wb-primary-light);
  background: var(--wb-primary-soft);
}

.mobile-tab-bar .tab-icon {
  font-size: 20px;
  line-height: 1;
}

.mobile-tab-bar .tab-label {
  font-weight: 500;
}

.wb-assistant-root.is-mobile {
  padding: 6px;
  gap: 8px;

  .wb-modal-backdrop {
    position: absolute;
  }

  .wb-header,
  .wb-bindings,
  .global-mode-panel,
  .wb-toolbar {
    padding: 6px;
    gap: 6px;
  }

  .toolbar-label {
    min-width: 100%;
  }

  .toolbar-select {
    width: 100%;
  }

  .worldbook-picker-trigger {
    white-space: normal;
  }

  .wb-main-layout {
    display: block !important;
    height: auto !important;
    overflow: visible !important;
  }

  .wb-entry-list,
  .wb-editor,
  .wb-editor-shell,
  .editor-side {
    width: 100% !important;
    height: auto !important;
    max-height: none !important;
    border: none !important;
    padding: 0 !important;
  }

  .wb-entry-list {
    max-height: 80vh !important;
    max-height: 80lvh !important;
    overflow-y: auto;
  }

  .wb-editor-shell {
    display: block !important;
  }

  .list-scroll {
    max-height: 60vh;
    max-height: 60lvh;
  }

  .wb-floating-window {
    position: absolute;
    left: 8px !important;
    right: 8px !important;
    width: auto !important;
    max-width: none !important;
  }
}

.list-actions {
  padding: 0 8px;
}

/* ─────────────────────────────────────────────────
   Override: Force theme colors on native form elements
   This beats SillyTavern global dark CSS which sets
   background/color on textarea, input, select, etc.
   ───────────────────────────────────────────────── */
.wb-assistant-root input,
.wb-assistant-root textarea,
.wb-assistant-root select,
.wb-assistant-root option,
.wb-assistant-root button {
  color: var(--wb-text-main) !important;
}

.wb-assistant-root input[type="text"],
.wb-assistant-root input[type="number"],
.wb-assistant-root textarea,
.wb-assistant-root select {
  background: var(--wb-input-bg) !important;
  border-color: transparent !important;
}

.wb-assistant-root input[type="text"]:hover,
.wb-assistant-root input[type="number"]:hover,
.wb-assistant-root textarea:hover,
.wb-assistant-root select:hover {
  background: var(--wb-input-bg-hover) !important;
}

.wb-assistant-root input[type="text"]:focus,
.wb-assistant-root input[type="number"]:focus,
.wb-assistant-root textarea:focus,
.wb-assistant-root select:focus {
  background: var(--wb-input-bg-focus) !important;
  border-color: var(--wb-primary-glow) !important;
  outline: none !important;
  box-shadow: 0 0 0 3px var(--wb-primary-soft) !important;
}
/* ═════════════════════════════════════════════════
   AI Generator Panel
   ═════════════════════════════════════════════════ */
.ai-generator-panel {
  display: flex;
  gap: 0;
  flex: 1;
  min-height: 0;
  border-radius: var(--wb-radius);
  overflow: hidden;
  background: var(--wb-bg-secondary);
}

/* ── Sidebar ── */
.ai-sidebar {
  width: 220px;
  min-width: 180px;
  border-right: 1px solid var(--wb-border);
  display: flex;
  flex-direction: column;
  background: var(--wb-bg-panel);
}

.ai-sidebar-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 12px;
  border-bottom: 1px solid var(--wb-border);
}

.ai-sidebar-title {
  font-weight: 600;
  font-size: 0.9em;
  color: var(--wb-text-main);
}

.ai-session-list {
  flex: 1;
  overflow-y: auto;
  padding: 6px;
}

.ai-session-item {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  width: 100%;
  padding: 8px 10px;
  margin-bottom: 2px;
  border: none;
  border-radius: var(--wb-radius-sm, 6px);
  background: transparent;
  cursor: pointer;
  text-align: left;
  transition: background 0.15s;
  position: relative;
  outline: none;
}

.ai-session-item:hover {
  background: var(--wb-bg-highlight);
}

.ai-session-item:focus-visible {
  box-shadow: 0 0 0 2px var(--wb-primary, #38bdf8);
}

.ai-session-item.active {
  background: var(--wb-primary-soft);
}

.ai-session-title {
  flex: 1;
  font-size: 0.85em;
  color: var(--wb-text-main);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.ai-session-meta {
  font-size: 0.72em;
  color: var(--wb-text-dim);
  width: 100%;
  margin-top: 2px;
}

.ai-session-delete {
  position: absolute;
  top: 4px;
  right: 4px;
  width: 20px;
  height: 20px;
  border: none;
  background: transparent;
  color: var(--wb-text-dim);
  font-size: 1em;
  cursor: pointer;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  opacity: 0;
  transition: opacity 0.15s, background 0.15s;
}

.ai-session-item:hover .ai-session-delete {
  opacity: 1;
}

.ai-session-delete:hover {
  background: var(--wb-danger, #e74c3c);
  color: #fff;
}

/* ── Chat Area ── */
.ai-chat-area {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-width: 0;
}

.ai-chat-empty {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 12px;
  color: var(--wb-text-dim);
}

.ai-chat-empty-icon {
  font-size: 3em;
  opacity: 0.5;
}

.ai-chat-empty-text {
  font-size: 0.95em;
}

.ai-chat-messages {
  flex: 1;
  overflow-y: auto;
  padding: 16px;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

/* ── Chat bubbles ── */
.ai-chat-bubble {
  max-width: 85%;
  padding: 10px 14px;
  border-radius: 12px;
  line-height: 1.55;
  white-space: pre-wrap;
  word-break: break-word;
}

.ai-chat-bubble.user {
  align-self: flex-end;
  background: var(--wb-primary-soft);
  border-bottom-right-radius: 4px;
}

.ai-chat-bubble.assistant {
  align-self: flex-start;
  background: var(--wb-bg-panel);
  border: 1px solid var(--wb-border);
  border-bottom-left-radius: 4px;
}

.ai-chat-bubble-role {
  font-size: 0.72em;
  font-weight: 600;
  color: var(--wb-text-dim);
  margin-bottom: 4px;
}

.ai-chat-bubble-content {
  font-size: 0.88em;
  color: var(--wb-text-main);
}

.ai-cursor {
  animation: ai-blink 0.7s infinite;
  color: var(--wb-primary);
}

@keyframes ai-blink {
  0%, 100% { opacity: 1; }
  50% { opacity: 0; }
}

.ai-thinking {
  color: var(--wb-text-dim);
  font-style: italic;
}

/* ── Input bar ── */
.ai-chat-input-bar {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  padding: 12px 16px;
  border-top: 1px solid var(--wb-border);
  background: var(--wb-bg-panel);
  align-items: flex-end;
}

.ai-context-toggle {
  width: 100%;
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 0.78em;
  color: var(--wb-text-dim);
  cursor: pointer;
  user-select: none;
}

.ai-context-toggle input {
  margin: 0;
}

.ai-context-toggle span {
  white-space: nowrap;
}

.ai-chat-input {
  flex: 1;
  resize: vertical;
  min-height: 40px;
  max-height: 140px;
  font-size: 0.88em;
}

.ai-send-btn,
.ai-stop-btn {
  min-width: 64px;
  height: 40px;
}

/* ═════════════════════════════════════════════════
   Tag Review Modal (API Settings / AI Config / Chat Extract)
   ═════════════════════════════════════════════════ */
.ai-tag-review-overlay {
  position: fixed;
  inset: 0;
  z-index: 10020;
  background: var(--wb-overlay-bg);
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 14px;
  box-sizing: border-box;
}

.ai-tag-review-modal {
  background: var(--wb-glass-bg);
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  border: 1px solid var(--wb-border-subtle);
  border-radius: 16px;
  box-shadow: 0 16px 48px rgba(0, 0, 0, 0.4), 0 2px 6px rgba(0, 0, 0, 0.1);
  width: 580px;
  max-width: 92vw;
  max-height: 80vh;
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

.ai-tag-review-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 16px 20px;
  border-bottom: 1px solid var(--wb-border-subtle);
  background: var(--wb-glass-header);
}

.ai-tag-review-title {
  font-weight: 600;
  font-size: 14px;
  color: var(--wb-text-main);
}

.ai-tag-review-close {
  width: 30px;
  height: 30px;
  border: 1px solid var(--wb-border-subtle);
  background: var(--wb-input-bg);
  color: var(--wb-text-main);
  font-size: 1.1em;
  cursor: pointer;
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: background 0.2s ease, border-color 0.2s ease, transform 0.2s ease;
}

.ai-tag-review-close:hover {
  background: var(--wb-input-bg-hover);
  border-color: #f43f5e;
  transform: translateY(-1px);
}

.ai-tag-review-target {
  padding: 14px 20px;
  border-bottom: 1px solid var(--wb-border-subtle);
}

.ai-tag-list {
  flex: 1;
  overflow-y: auto;
  padding: 10px 20px;
}

.ai-tag-item {
  display: flex;
  align-items: flex-start;
  gap: 12px;
  padding: 12px 0;
  border-bottom: 1px solid var(--wb-border-subtle);
  cursor: pointer;
  transition: background 0.15s ease;
}

.ai-tag-item:last-child {
  border-bottom: none;
}

.ai-tag-item:hover {
  background: var(--wb-primary-soft);
  border-radius: 8px;
  margin: 0 -8px;
  padding: 12px 8px;
}

.ai-tag-item input[type="checkbox"] {
  margin-top: 3px;
}

.ai-tag-info {
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: 6px;
  min-width: 0;
}

.ai-tag-name {
  font-weight: 600;
  font-size: 13px;
  color: var(--wb-primary-light);
}

.ai-tag-preview {
  font-size: 12px;
  color: var(--wb-text-dim);
  white-space: pre-wrap;
  word-break: break-all;
  line-height: 1.5;
}

.ai-tag-review-actions {
  display: flex;
  gap: 8px;
  padding: 14px 20px;
  border-top: 1px solid var(--wb-border-subtle);
  justify-content: flex-end;
  background: var(--wb-glass-header);
}

.btn.primary {
  background: var(--wb-primary);
  color: #fff;
  border-color: var(--wb-primary);
}

.btn.primary:hover {
  filter: brightness(1.1);
}

.btn.primary:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

/* ═════════════════════════════════════════════════
   Mobile Responsive
   ═════════════════════════════════════════════════ */
.wb-assistant-root.is-mobile {
  padding: 6px;
  gap: 6px;
  border-radius: 0;

  /* ── Toolbar ── */
  .toolbar-label {
    min-width: unset;
    width: 100%;
  }

  .toolbar-label select {
    flex: 1;
    min-width: 0;
  }

  .toolbar-btns {
    width: 100%;
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
  }

  .toolbar-btns .btn {
    font-size: 0.78em;
    padding: 4px 8px;
  }

  /* ── Bindings bar ── */
  .wb-bindings {
    flex-wrap: wrap;
    gap: 4px;
    padding: 6px 8px;
    font-size: 0.78em;
  }

  /* ── Main layout ── */
  .wb-main-layout {
    display: block !important;
    overflow: visible;
    flex: none;
  }

  .wb-resize-handle {
    display: none !important;
  }

  .wb-entry-list,
  .wb-editor {
    min-height: 0;
    max-height: none;
  }

  /* ── AI Generator Panel ── */
  .ai-generator-panel {
    flex-direction: column;
  }

  .ai-sidebar {
    width: 100%;
    min-width: unset;
    max-height: 110px;
    border-right: none;
    border-bottom: 1px solid var(--wb-border);
  }

  .ai-sidebar-head {
    padding: 6px 10px;
  }

  .ai-session-list {
    overflow-x: auto;
    overflow-y: hidden;
    display: flex;
    flex-direction: row;
    gap: 4px;
    padding: 4px 8px;
  }

  .ai-session-item {
    flex-shrink: 0;
    min-width: 140px;
    max-width: 200px;
  }

  .ai-chat-messages {
    padding: 10px;
    gap: 8px;
  }

  .ai-chat-bubble {
    max-width: 95%;
  }

  .ai-chat-input-bar {
    padding: 8px 10px;
    gap: 6px;
  }

  .ai-chat-input {
    min-height: 36px;
    font-size: 0.85em;
  }

  /* ── Tag review modal (mobile full-screen) ── */
  .ai-tag-review-overlay {
    position: absolute;
    inset: 0;
    padding: 0;
    z-index: 10200;
    align-items: stretch;
    justify-content: stretch;
  }

  .ai-tag-review-modal {
    width: 100% !important;
    max-width: 100% !important;
    max-height: 100% !important;
    height: 100%;
    border-radius: 0;
    border: none;
    box-shadow: none;
  }

  .ai-tag-review-head {
    padding: 12px 14px;
    flex-shrink: 0;
  }

  .ai-tag-review-title {
    font-size: 13px;
  }

  .ai-tag-review-close {
    width: 28px;
    height: 28px;
    font-size: 1em;
  }

  .ai-tag-review-target {
    padding: 10px 14px;
    flex-shrink: 0;
  }

  .ai-tag-list {
    flex: 1;
    min-height: 0;
    overflow-y: auto;
    -webkit-overflow-scrolling: touch;
    padding: 8px 14px;
  }

  .ai-tag-item {
    padding: 10px 0;
    gap: 10px;
  }

  .ai-tag-item:hover {
    margin: 0;
    padding: 10px 0;
    background: transparent;
  }

  .ai-tag-review-actions {
    flex-wrap: wrap;
    gap: 6px;
    padding: 10px 14px;
    flex-shrink: 0;
  }

  .ai-tag-review-actions .btn {
    flex: 1;
    min-width: 0;
    font-size: 12px;
    padding: 8px 10px;
  }

  /* Override inline max-height on modal body scrollable divs */
  .ai-tag-review-modal > div:not(.ai-tag-review-head):not(.ai-tag-review-actions):not(.ai-tag-review-target):not(.ai-tag-list):not(.ai-tag-ignore-config) {
    max-height: none !important;
    flex: 1;
    min-height: 0;
    overflow-y: auto !important;
    -webkit-overflow-scrolling: touch;
  }

  /* AI config preview table horizontal scroll */
  .ai-tag-review-modal table {
    display: block;
    overflow-x: auto;
    -webkit-overflow-scrolling: touch;
    font-size: 12px;
  }

  /* ── Status footer ── */
  .wb-status {
    font-size: 0.72em;
    padding: 4px 8px;
    gap: 6px;
  }

  /* ── Editor content area ── */
  .editor-content-area {
    flex: 1;
    min-height: 40vh;
    min-height: 40lvh;
  }

  .content-resize-handle {
    display: flex;
    height: 28px;
  }

  .editor-content-block {
    position: relative;
    z-index: 10;
    background: var(--wb-bg-root);
  }

  .content-top-drag-handle {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 22px;
    cursor: ns-resize;
    background: var(--wb-bg-panel);
    border-radius: 8px 8px 0 0;
    touch-action: none;
    user-select: none;
  }

  .content-top-drag-grip {
    font-size: 12px;
    color: var(--wb-text-dim);
    letter-spacing: 3px;
    line-height: 1;
  }

  .text-area.compact {
    min-height: 60px;
  }

  .editor-center {
    padding: 8px;
  }

  .editor-side {
    padding: 8px;
  }

  .editor-grid.two-cols {
    grid-template-columns: 1fr;
  }
}
